经典查找算法开发环境Linux，vim
编程语言：C语言
顺序查找法从序列的一端开始遍历到另一端，找到对应元素则返回对应下标（或做其他处理），找不到则返回-1.
&#x3D;&#x3D;可能查找得到，也可能查找不到&#x3D;&#x3D;。
时间复杂度是O(n)
ASL &#x3D; (1+2+3+…+n)&#x2F;n&#x3D;(1+n)*n&#x2F;2&#x2F;n&#x3D;(1+n)&#x2F;2
int querySearch(int arr[],int length,int key) &#123;
    for (int i &#x3D; 0;i &lt; length; i++) &#123;
        if (key &#x3D;&#x3D; arr[i]) return i;
    &#125;
    return -1;
&#125;



哨兵法查找选取头部（尾部）位置做哨兵，从尾部（头部）开始遍历到头部（尾部），找到对应元素则返回对应下标。
原来的内存中有一个单元是不用的，这个单元用来存储哨兵。
&#x3D;&#x3D;一定会查找得到&#x3D;&#x3D;。
&#x3D;&#x3D;和顺序查找是一个意思&#x3D;&#x3D;。
&#x2F;&#x2F;0号位置不放原始数据，用于存储哨兵（待查找的数据）
int querySearch(int arr[],int length,int key) &#123;
    arr[0] &#x3D; key;
    while(arr[0] !&#x3D; arr[--length]);
    return length;
&#125;

时间复杂度是O(n)
二分查找法前提：&#x3D;&#x3D;序列有序，并且是顺序存储&#x3D;&#x3D;。因为链表不能跳着访问。
每一次都是拿要查找的数和子序列的中间位置比较，如果要查找的数比中间位置的小就往左边继续找，如果要查找的数比中间位置的大就往 右边继续找，如果要查找的数和中间位置的数一样大就结束递归返回中间位置的下标，经历了多次这样的寻找后仍然找不到就说明序列中没有这个数直接返回-1.
循环写法：
int binarySearch(int arr[],int left,int right,int key) &#123;
    int mid;
    while (left &lt;&#x3D; right) &#123;
        mid &#x3D; left + (right - left)&#x2F;2;
        if (key &lt; arr[mid]) right &#x3D; mid - 1;
        else if(key &gt; arr[mid]) left &#x3D; mid + 1;
        else return mid;
    &#125;
    return -1;
&#125;

递归写法：
int binarySearch(int arr[],int left,int right,int key) &#123;
    if (left &gt; right) return -1;
    int mid &#x3D; left + (right - left)&#x2F;2;
	if (key &lt; arr[mid]) binarySearch(arr,left,mid - 1,key);
    else if(key &gt; arr[mid]) binarySearch(arr,mid + 1,right,key);
    else return mid;
&#125;

时间复杂度是O(logn)
1   n&#x2F;2
2   n&#x2F;2&#x2F;2
3   n&#x2F;2&#x2F;2&#x2F;2
…
x &#x3D; logn
分块查找法需要一个符号表，存储序列中几个比较特殊的元素，在查找之前先在符号表找一遍，然后再到对应的区域进行查找操作。同样的也是找到就返回对应的下标，否则返回-1.
符号表的结构体描述：
typedef struct Data &#123;
	int key;
	int index;
&#125;Data, ST;

int blocksearch(int arr[], int length, ST* st, int len_st, int key) &#123;
	int left &#x3D; 0, right &#x3D; len_st - 1;
	int mid &#x3D; left + ((right - left) &gt;&gt; 1);
	&#x2F;&#x2F;二分法查找区间
    while (left &lt; right) &#123;
		if (key &lt; st[mid].key)  	  right &#x3D; mid; &#x2F;&#x2F;因为最大值包含在其中，所有不能漏掉right所对应的值
		else if (key &gt; st[mid].key)	  left &#x3D; mid + 1; &#x2F;&#x2F;因为left所有对应的比过了，就直接跳开
		else break;
		mid &#x3D; left + ((right - left) &gt;&gt; 1);
	&#125;
	int begin &#x3D; st[mid].index;
	int end &#x3D; mid &gt;&#x3D; len_st - 1 ? length : st[mid + 1].index;
	&#x2F;&#x2F;在对应的区间中顺序查找
    while (begin &lt; end) &#123;
		if (key &#x3D;&#x3D; arr[begin]) return begin;
		begin++;
	&#125;
	return -1;
&#125;

void printElement(int arr[], int length, int index) &#123;
	if (index &lt; 0 || index &gt;&#x3D; length)
		printf(&quot;下标越界\n&quot;);
	else
		printf(&quot;index &#x3D; %d\tvalue &#x3D; %d\n&quot;, index, arr[index]);
&#125;

int main() &#123;
	srand((unsigned int)time(NULL));
	int arr[15] &#x3D; &#123; 5,7,9,1,3 ,24,26,28,22,21,47,57,42,56,37 &#125;;
	showArr(arr, 15);
	ST st[3] &#x3D; &#123;
		&#123;9,0&#125;,
		&#123;28,5&#125;,
		&#123;57,10&#125;
	&#125;;
	int index &#x3D; blocksearch(arr, 15, st, 3, 50);
	printElement(arr, sizeof(arr) &#x2F; sizeof(arr[0]), index);
	return 0;
&#125;


O(logk+m)
二叉查找树查找法解决&#x3D;&#x3D;链式存储结构&#x3D;&#x3D;的查找。封装一个有序二叉树，该树的特征是中序遍历是有序的（所以又叫二叉排序树），并且每一颗子树中的父亲都比左子树大并且比右子树小。查找的时候就从根部开始向下查找，如果小于则往左边找，大于则往右边找，等于就直接返回，如果都遍历到底部了仍然没有找到就返回NULL.
类似二分查找。
适合动态增加和删除的查找算法。
时间复杂度：

一般是O(logn)
最坏情况：O(n)

当二叉查找形成一边倒的时候就会出现最坏情况，这个时候的查找变成是链表的顺序查找（没有发挥出二叉树的优势）了，就慢了很多。
二叉查找树的结构体描述：
typedef struct BSTree
&#123;
	int key;
	struct BSTree* lchild;
	struct BSTree* rchild;
&#125;BSTree,Node;

二叉查找树的几个相关函数
Node* createNode(int data);
BSTree* insertNode(BSTree* tree, int data);
Node* deleteNode(BSTree* tree, int key);
Node* searchNode(BSTree* tree, int key);
void show_mid(BSTree* tree);

对应相关函数的实现：
创建二叉查找树：
Node* createNode(int data) &#123;
	Node* newNode &#x3D; (Node*)malloc(sizeof(Node));
	assert(newNode);
	newNode-&gt;key &#x3D; data;
	newNode-&gt;lchild &#x3D; NULL;
	newNode-&gt;rchild &#x3D; NULL;
	return newNode;
&#125;

向二叉查找树插入数据：
二叉查找树在插入数据的时候，都是把数据插入到树的叶子位置。
BSTree* insertNode(BSTree* tree, int data) &#123;
	if (tree &#x3D;&#x3D; NULL) return createNode(data);
	Node* pMove &#x3D; tree;
	Node* pBack &#x3D; NULL;
	while (pMove) &#123;
		pBack &#x3D; pMove;
		pMove &#x3D; data &lt; pMove-&gt;key ? pMove-&gt;lchild : pMove-&gt;rchild;
	&#125;
	if (data &lt; pBack-&gt;key)	 	pBack-&gt;lchild &#x3D; createNode(data);
	else 						pBack-&gt;rchild &#x3D; createNode(data);
	return tree;
&#125;

删除时需要的辅助函数：
&#x2F;&#x2F;找最大节点 最右边
Node* maxKeyNode(BSTree* tree) &#123;
	if (tree &#x3D;&#x3D; NULL) return NULL;
	while (tree-&gt;rchild)
		tree &#x3D; tree-&gt;rchild;
	return tree;
&#125;

在二叉查找树中删除节点：
首先先通过左右指针寻找，key和当前节点的key比较，小了就往左边走，大了就往右边走，等于的时候就停下来，删除它。
删除的时候，使用当前节点的左子树的最大值maxNode覆盖掉当前节点的key，然后再遍历到maxNode的位置将maxNode释放内存。这样做的好处是不需要大幅度改变原来树的结构，理解起来也比较简单。实现的时候采用递归的写法实现，这样比较简单，当然使用循环实现也是可以的，但是使用循环来实现比较麻烦。
Node* deleteNode(BSTree* tree, int key) &#123;
	if (tree &#x3D;&#x3D; NULL) return NULL;
	if (key &lt; tree-&gt;key)		tree-&gt;lchild &#x3D; deleteNode(tree-&gt;lchild, key);
	else if (key &gt; tree-&gt;key)	tree-&gt;rchild &#x3D; deleteNode(tree-&gt;rchild, key);
	else &#123;		&#x2F;&#x2F;tree对应要删除的节点
		if (tree-&gt;lchild !&#x3D; NULL &amp;&amp; tree-&gt;rchild !&#x3D; NULL) &#123;
			Node* max &#x3D; maxKeyNode(tree-&gt;lchild);
			tree-&gt;key &#x3D; max-&gt;key;
			tree-&gt;lchild &#x3D; deleteNode(tree-&gt;lchild, max-&gt;key);
		&#125;
		else &#123;
			Node* temp &#x3D; tree;
			tree &#x3D; tree-&gt;lchild ? tree-&gt;lchild : tree-&gt;rchild;
			free(temp);
		&#125;
	&#125;
	return tree;
&#125;

二叉查找的查找：
Node* searchNode(BSTree* tree, int key) &#123;
	Node* pMove &#x3D; tree;
	while (pMove &amp;&amp; pMove-&gt;key !&#x3D; key) &#123;
		if (key &lt; pMove-&gt;key)			pMove &#x3D; pMove-&gt;lchild;
		else if (key &gt; pMove-&gt;key)		pMove &#x3D; pMove-&gt;rchild;
		else 							break;
	&#125;
	return pMove;
&#125;

树的中序遍历：
void show_mid(BSTree* tree) &#123;
	if (tree &#x3D;&#x3D; NULL) return;
	show_mid(tree-&gt;lchild);
	printf(&quot;%d &quot;, tree-&gt;key);
	show_mid(tree-&gt;rchild);
&#125;

主函数测试：
#include &lt;stdio.h&gt;
#include &quot;bstree.h&quot;

void sort(int arr[], int length) &#123;
	for (int i &#x3D; 0; i &lt; length; i++) &#123;
		for (int j &#x3D; i + 1; j &lt; length; j++) &#123;
			if (arr[j] &lt; arr[i]) &#123;
				int temp &#x3D; arr[i];
				arr[i] &#x3D; arr[j];
				arr[j] &#x3D; temp;
			&#125;
		&#125;
	&#125;
&#125;

int main() &#123;
	int arr[10] &#x3D; &#123; 5,4,7,1,3,2,6,8,9,0 &#125;;
	BSTree* tree &#x3D; NULL;
	for (int i &#x3D; 0; i &lt; 10; i++) &#123;
		tree &#x3D; insertNode(tree, arr[i]);
	&#125;
	sort(arr, 10);
	show_mid(tree);
	&#x2F;&#x2F;tree &#x3D; deleteNode(tree, 6);
	Node* p &#x3D; searchNode(tree, 6);
	&#x2F;&#x2F;show_mid(tree);
	if (p &#x3D;&#x3D; NULL) &#123;
		printf(&quot;\n找不到\n&quot;);
	&#125;
	else &#123;
		printf(&quot;\n地址: %p\t值: %d\n&quot;, p, p-&gt;key);
	&#125;
	return 0;
&#125;



平衡二叉树查找法解决有序二叉树一边倒（变成顺序查找，失去了二叉树的优势）或高度不平衡的情况导致查找效率低的问题。
&#x3D;&#x3D;平衡二叉树是树的左右高度差不超过2的二叉查找树&#x3D;&#x3D;。
因为平衡二叉树由苏联计算机科学家发明，所以又以科学家的名字命名称为AVL树。
关于平衡二叉树，我以前已经单独写过博客了，直接链接到以前的博客即可，链接如下：
https://blog.csdn.net/qq_53744721/article/details/124206478
哈希表查找元素的存储位置和其关键字之间建立某种直接关系，那么在进行查找时，就无需做比较或做很少次的比较，按照这种关系直接由关键字找到相应的记录。这就是散列查找法的思想。
H(k) &#x3D; k%3
散列法的几个术语：

散列函数和散列地址
在记录的存储位置address和其关键字key之间建立一个确定的对应关系H，使address&#x3D;H(key)，称这个对应关系H为散列函数，address为散列地址。

散列表
一个有限连续的地址空间，用以存储按散列函数计算得到相应散列地址的数据记录。通常散列表的存储空间是一个一维数组。散列地址是数字下标。

冲突和同义词
对不同的关键字可能得到同一个散列地址，即key1 !&#x3D; key2, 而H(key1)&#x3D;H(key2), 这种现象称为冲突。


存储的数据类型结构体描述：
typedef struct Data &#123;
	int data;
	int index;
&#125;Data;

传统数组版哈希表结构体描述：
typedef struct Hash
&#123;
	Data key;
	int search_count;
&#125;Hash;

哈希函数：以取模为例
int HashFunc(int key, int length) &#123;
	return key % length;
&#125;

创建哈希表：
Hash* createHash(int arr[], int arrLen, int hashLen) &#123;
	Hash* hash &#x3D; (Hash*)calloc(hashLen, sizeof(Hash));
	assert(hash);
	int address;
	int count;
	for (int i &#x3D; 0; i &lt; arrLen; i++) &#123;
		address &#x3D; HashFunc(arr[i], hashLen);
		count &#x3D; 1;
		while (hash[address].search_count !&#x3D; 0) &#123;
			address &#x3D; (address + 1) % hashLen;
			count++;
		&#125;
		hash[address].key.data &#x3D; arr[i];
		hash[address].key.index &#x3D; i;
		hash[address].search_count &#x3D; count;
	&#125;
	return hash;
&#125;

打印哈希表：
void printHashTable(Hash* hash, int length) &#123;
	printf(&quot;key\tsearch\n&quot;);
	for (int i &#x3D; 0; i &lt; length; i++) &#123;
		printf(&quot;%d\t%d\n&quot;, hash[i].key.data, hash[i].search_count);
	&#125;
	printf(&quot;\n---------------------------\n&quot;);
&#125;

哈希查找：
Data hashSearch(Hash* hash, int length, int key) &#123;
	Data ret;
	ret.data &#x3D; key;
	int address &#x3D; HashFunc(key, length);
	int flag &#x3D; address;
	while (hash[address].key.data !&#x3D; key &amp;&amp; hash[address].search_count !&#x3D; 0) &#123;
		address &#x3D; (address + 1) % length;
		if (address &#x3D;&#x3D; flag)
			break;
	&#125;
	ret.index &#x3D; hash[address].key.data &#x3D;&#x3D; key ? address : -1;
	return ret;
&#125;

主函数测试：
int main() &#123;
	int arr[10] &#x3D; &#123; 15,20,45,6,7,8,16,33,24,67 &#125;;
	Hash* hash &#x3D; createHash(arr, 10, 20);
	printHashTable(hash, 20);
	int key &#x3D; 28;
	Data result &#x3D; hashSearch(hash, 20, key);
	printf(&quot;找到%d在%d\n&quot;, result.data, result.index);
	return 0;
&#125;



红黑树查找法红黑树是一种特化的AVL树（平衡二叉树），都是在进行插入和删除操作时通过特定操作保持二叉查找树的平衡，从而获得较高的查找性能。
红黑树很复杂，但它的最坏情况运行时间也是非常良好的，并且在实践中是高效的： 它可以在O(log n)时间内做查找，插入和删除。
红黑树和AVL树的比较
查找效率：AVL树查找效率比红黑树高，因为AVL树的左右高度很平衡，而红黑树和AVL树的查找又是基于二叉查找树的，所以AVL树的查找效率比红黑树高。
综合效率：红黑树的效率比AVL树的高，因为AVL树在建立（插入数据）的时候，为了满足树的高度差不超过1，所以频繁的调整导致效率变低，而红黑树调整的没有AVL树频繁，所以综合效率往往是红黑树比AVL高。
红黑树的特征：
红黑树是每个结点都带有颜色属性的二叉查找树，颜色或红色或黑色。 在二叉查找树强制一般要求以外，对于任何有效的红黑树我们增加了如下的额外要求

节点非黑即红
根节点是黑色的
所有叶子节点是黑色的
每个红色结点的两个子结点都是黑色。（从每个叶子到根的所有路径上不能有两个连续的红色结点）
从任一结点到其每个叶子的所有路径都包含相同数目的黑色结点

这些约束强制了红黑树的关键性质:  &#x3D;&#x3D;从根到叶子的最长的可能路径不多于最短的可能路径的两倍长&#x3D;&#x3D;。结果是这个树大致上是平衡的。因为操作比如插入、删除和查找某个值的最坏情况时间都要求与树的高度成比例，这个在高度上的理论上限允许红黑树在最坏情况下都是高效的，而不同于普通的二叉查找树。

8.1 String类用于管理字符串的类。类似C++的string类
8.1.1 构造String对象String常量String常量也是对象，是用双引号括起来的字符序列。Java把用户程序中的String常量放入常量池。因为String常量是对象，所以也有自己的引用和实体。
注意：可以这样简单地理解常量池，常量池中的数据在程序运行期间再也不允许改变。
String对象可以使用String类声明对象并创建对象。例如：
String s &#x3D; new String(&quot;Hello&quot;);

对象变量s中存放着引用，表明自己的实体的位置，即new运算符首先分配内存空间并在内存空间中存放字符序列。
可以查看引用地址确认String类的实际存储位置：
int idetityHashCode(Object object);

String类常用的构造方法&#x2F;&#x2F; 1
char[] a &#x3D; &#123;&#39;H&#39;, &#39;e&#39;, &#39;l&#39;, &#39;l&#39;, &#39;o&#39;&#125;;
String s &#x3D; new String(a);
&#x2F;&#x2F; 相当于 String s &#x3D; new String(&quot;Hello&quot;);

&#x2F;&#x2F; 2
char[] b &#x3D; &#123;&#39;W&#39;, &#39;o&#39;, &#39;r&#39;, &#39;l&#39;, &#39;d&#39;&#125;;
String s2 &#x3D; new String(b, 1, 3);  &#x2F;&#x2F; orl

引用String常量常量实际地址是不变的，当使用两个String对象相互赋值，其实是将常量池的数据的地址赋值。
不可变对象所谓不可变对象是指对象的变量中存储的值不能再发生改变。String对象属于不可变变量，即String对象的实体无法再发生变化，其原因是String类是final类，String也没有给其对象提供修改实体的方法。
8.1.2 String对象的并置就是字符串连接。
String hello &#x3D; &quot;Hello&quot;;
String world &#x3D; &quot;World&quot;;
String helloworld &#x3D; hello + world; &#x2F;&#x2F; helloworld获得的是一个新的地址，而不是由hello的地址上增加内容

注意：程序更关心两个String对象的实体，而不是二者的引用是否相同。
8.1.3 String的常用方法
length 获取字符串长度。

String hello &#x3D; &quot;Hello你好&quot;;
int len &#x3D; hello.length(); &#x2F;&#x2F; 7


equals 判断两个字符串

String tom &#x3D; new String(&quot;天道酬勤&quot;);
String boy &#x3D; new String(&quot;知心朋友&quot;);
String jerry &#x3D; new String(&quot;天道酬勤&quot;);
boolean b &#x3D; tom.equals(boy); &#x2F;&#x2F; false
b &#x3D; tom.equals(jerry);  &#x2F;&#x2F; true

注意：tom==boy这种方式是比较这两个引用是否相等，而不是比较字符串是否相等。

startsWith 判断字符串是否以什么开头

String hello &#x3D; &quot;Hello&quot;;
boolean b &#x3D; hello.startsWith(&quot;Hel&quot;); &#x2F;&#x2F; true
b &#x3D; hello.startsWith(&quot;he&quot;); &#x2F;&#x2F; false


endsWith 判断字符串是否以什么结尾

String hello &#x3D; &quot;Hello&quot;;
boolean b &#x3D; hello.endsWith(&quot;lo&quot;); &#x2F;&#x2F; true
b &#x3D; hello.endsWith(&quot;ll&quot;); &#x2F;&#x2F; false


compareTo 比较两个字符串

