随机获得6个1~100的不同的整数。
import java.util.Random;

class GetRandomNumber &#123;
    public static int[] getRandomNumber(int max, int amount) &#123;
        &#x2F;&#x2F; 1~max随机整数
        int[] randNumber &#x3D; new int[amount];
        int index &#x3D; 0;
        randNumber[0] &#x3D; -1;
        Random random &#x3D; new Random();
        while (index &lt; amount) &#123;
            int number &#x3D; random.nextInt(max) + 1;   &#x2F;&#x2F; [1, max]
            boolean isInArrays &#x3D; false;
            for (int m : randNumber) &#123;
                if (m &#x3D;&#x3D; number) &#123;
                    isInArrays &#x3D; true;
                    break;
                &#125;
            &#125;
            if (!isInArrays) &#123;
                randNumber[index++] &#x3D; number;
            &#125;
        &#125;
        return randNumber;
    &#125;
&#125;

public class Main &#123;
    public static void main(String[] args) &#123;
        int[] a &#x3D; GetRandomNumber.getRandomNumber(100, 6);
        System.out.println(java.util.Arrays.toString(a));
    &#125;
&#125;
