                ShowMessage sm &#x3D; (s) -&gt; &#123;
                        System.out.println(&quot;tvtvtvtvtvtvtv&quot;);
                        System.out.println(s);
                        System.out.println(&quot;tvtvtvtvtvtvtv&quot;);
                &#125;;
                sm.show(&quot;电视机&quot;);
                sm &#x3D; (s) -&gt; &#123;
                        System.out.println(&quot;pcpcpcpcpcpcpc&quot;);
                        System.out.println(s);
                        System.out.println(&quot;pcpcpcpcpcpcpc&quot;);
                &#125;;
                sm.show(&quot;电脑&quot;);
        &#125;
&#125;

